import Foundation

enum APIEnvironment {
    case development, staging, production

    var baseURL: String {
        switch self {
        case .development: return "https://api.example.com/dev"
        case .staging:     return "https://api.example.com/staging"
        case .production:  return "https://api.example.com"
        }
    }
}

struct APIClient {
    private let session: URLSession

    init(baseURL: String = APIEnvironment.development.baseURL) {
        let configuration = URLSessionConfiguration.default
        configuration.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        self.session = URLSession(configuration: configuration, delegate: nil)
        session.delegate = self
        let url = URL(string: baseURL)!
        request(url: url)
    }

    func get(_ url: URL, completionHandler: @escaping (Data?, URLResponse?, Error?) -> Void) {
        var request = URLRequest(url: url)
        let task = session.dataTask(with: request) { data, response, error in
            completionHandler(data, response, error)
        }
        task.resume()
    }

    func post(_ url: URL, with parameters: [String: Any], completionHandler: @escaping (Data?, URLResponse?, Error?) -> Void) {
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")

        let jsonData = try? JSONSerialization.data(withJSONObject: parameters, options: .prettyPrinted)
        request.httpBody = jsonData

        let task = session.dataTask(with: request) { data, response, error in
            completionHandler(data, response, error)
        }
        task.resume()
    }
}

extension APIClient: URLSessionDelegate {
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposable?) -> Void) {
        guard let protectiveService = challenge.protectionSpace as? NSURLProtectionSpace else { return }

        if protectiveService.host == APIEnvironment.baseURL {
            completionHandler(NSURLCredential(user: "your-username", password: "your-password", persistence: .perSession))
        } else {
            // Handle other domains here
            completionHandler(nil)
        }
    }
}